# Production-scale prompt optimization with A/B testing (cricket_league context)
import json
from dataclasses import dataclass

@dataclass
class PromptVariant:
    name: str
    template: str
    performance_metrics: dict

# Two competing prompts for cricket player performance prediction
variant_aggressive = PromptVariant(
    name="aggressive_variant",
    template="""You are an expert cricket analyst. Given player stats, predict their next match performance.

    Player: {player_name}
    Recent avg: {recent_avg}
    Venue: {venue}
    Opposition: {opposition}

    Provide: 1) Predicted runs (lower/middle/upper bound), 2) Confidence %, 3) Key factors.
    Format as JSON.""",
    performance_metrics={"accuracy": 0.82, "latency_ms": 245, "cost_per_call": 0.008}
)

variant_conservative = PromptVariant(
    name="conservative_variant",
    template="""You are a cautious cricket analyst. Step through this analysis carefully.

    Think about: player form, venue conditions, opposition strengths, recent match context.

    Player: {player_name}
    Stats: {recent_avg}, {venue}, {opposition}

    Step 1: Assess current form
    Step 2: Evaluate venue impact
    Step 3: Consider opposition
    Step 4: Predict runs with confidence

    Output JSON with bounds and reasoning.""",
    performance_metrics={"accuracy": 0.88, "latency_ms": 412, "cost_per_call": 0.012}
)

# A/B testing framework
def select_optimal_prompt(variants: list, metric: str = "accuracy") -> str:
    """Select best-performing prompt variant for production deployment."""
    winner = max(variants, key=lambda v: v.performance_metrics.get(metric, 0))
    return winner.name

chosen = select_optimal_prompt([variant_aggressive, variant_conservative], "accuracy")
print(f"Deploy {chosen}: Higher accuracy justifies 40% latency cost.")
